export function createExecution(id: string, initial?: Partial<Omit<ExecutionRecord, "id">>): ExecutionRecord {
  const ts = now();
  const record: ExecutionRecord = { id, status: initial?.status ?? "started", createdAt: initial?.createdAt ?? ts, updatedAt: initial?.updatedAt ?? ts, ...(initial?.result !== undefined ? { result: initial.result } : {}) };
  executions.set(id, record);
  return record;
}

